<?php
namespace Zclone\controllers; use Zclone\Core\Database; use Zclone\Core\Request; use Zclone\Core\Response; use Zclone\repositories\PlanetRepository; final class DashboardController { public function __construct(private PlanetRepository $planets, private Database $db) {} public function index(Request $r): void { $planet=$this->planets->homeworld($r->userId()); $buildings=$planet?$this->db->all('select * from planet_buildings where planet_id=?',[$planet['id']]):[]; Response::view('dashboard',['planet'=>$planet,'buildings'=>$buildings]); } public function fleet(Request $r): void { Response::view('fleet'); } public function galaxy(Request $r): void { Response::view('galaxy'); } public function tech(Request $r): void { Response::view('tech'); } public function alliance(Request $r): void { Response::view('alliance'); } public function market(Request $r): void { Response::view('market'); } public function messages(Request $r): void { Response::view('messages'); } }
